const CRITICAL_PAIRS = {
    linguistic: [['b', 'd'], ['p', 'q'], ['m', 'n'], ['u', 'n'], ['a', 'e'], ['s', 'z'], ['t', 'f'], ['ğ', 'g'], ['ı', 'i'], ['v', 'y']],
    numeric: [['6', '9'], ['2', '5'], ['1', '7'], ['0', '8'], ['3', '8'], ['4', '7']],
    semantic: [['dere', 'dede'], ['baba', 'dada'], ['kasa', 'masa'], ['kale', 'lale'], ['kitap', 'katip'], ['sarı', 'darı'], ['para', 'yara'], ['kuzu', 'kutu']],
    pictographic: [['▲', '▼'], ['◀', '▶'], ['⬈', '⬉'], ['◐', '◑'], ['◒', '◓'], ['◖', '◗']]
};

const generateProceduralPolygon = (points: number) => {
    let d = "M 50 10";
    for (let i = 1; i < points; i++) {
        const angle = (i * 360 / points) * Math.PI / 180;
        const x = 50 + 40 * Math.sin(angle);
        const y = 50 - 40 * Math.cos(angle);
        d += ` L ${x} ${y}`;
    }
    return d + " Z";
};

export const generateOfflineVisualOddOneOut = async (options: GeneratorOptions): Promise<VisualOddOneOutData[]> => {
    const { worksheetCount, itemCount, difficulty, distractionLevel, gridSize } = options;
    const results: VisualOddOneOutData[] = [];

    for (let p = 0; p < worksheetCount; p++) {
        const rowCount = itemCount || 8;
        const colCount = gridSize || 4;
        const rows = [];

        for (let i = 0; i < rowCount; i++) {
            const items: VisualOddOneOutItem[] = [];
            const correctIndex = getRandomInt(0, colCount - 1);

            // Base Item Construction
            const polyPoints = getRandomInt(3, 8);
            const baseD = generateProceduralPolygon(polyPoints);
            const baseItem: VisualOddOneOutItem = {
                svgPaths: [{ d: baseD, stroke: "#1e293b", strokeWidth: 3 }],
                rotation: 0
            };

            for (let j = 0; j < colCount; j++) {
                if (j === correctIndex) {
                    // Create Odd Item based on distractionLevel
                    const oddItem = { ...JSON.parse(JSON.stringify(baseItem)) };
                    if (distractionLevel === 'low') {
                        oddItem.svgPaths[0].stroke = "#ef4444"; // Color difference
                    } else if (distractionLevel === 'medium') {
                        oddItem.rotation = 90; // Distinct rotation
                    } else if (distractionLevel === 'high') {
                        oddItem.rotation = 15; // Subtle rotation
                        oddItem.svgPaths[0].strokeWidth = 1.5; // Subtle weight
                    } else {
                        oddItem.isMirrored = true; // Harder perception
                        oddItem.scale = 0.9;
                    }
                    items.push(oddItem);
                } else {
                    items.push({ ...JSON.parse(JSON.stringify(baseItem)) });
                }
            }

            rows.push({ items, correctIndex, reason: "Prosedürel Geometri Farkı" });
        }

        results.push({
            title: "Görsel Ayrıştırma: Farklı Olanı Bul",
            instruction: "Her satırdaki şekilleri dikkatlice inceleyin. Diğerlerinden farklı olan şekli bulun ve altındaki kutucuğu işaretleyin.",
            pedagogicalNote: "Bu çalışma; şekil-zemin algısı, görsel sabitlik ve uzamsal ilişkileri ayırt etme becerilerini klinik düzeyde destekler.",
            difficultyLevel: difficulty as any || 'Orta',
            distractionLevel: distractionLevel as any || 'medium',
            rows
        });
    }
    return results;
};

