export const generateMapInstructionFromAI = async (options: GeneratorOptions): Promise<MapInstructionData[]> => {
    const { worksheetCount, difficulty, studentContext, emphasizedRegion, itemCount, showCityNames } = options;

    const regionDesc = emphasizedRegion === 'all' ? 'Tüm Türkiye' : `${emphasizedRegion} Bölgesi`;
    const cityVisibility = showCityNames ? "Şehir isimleri haritada GÖRÜNÜR olacak." : "Şehir isimleri haritada GİZLİ olacak (Bellek testi odaklı).";

    const prompt = `
    [ROL: KIDEMLİ COĞRAFYA PROFESÖRÜ VE ÖZEL EĞİTİM UZMANI]
    [MODEL: Gemini 3.0 Flash Preview Multimodal - COĞRAFİ ANALİZ MODU]

    ${getStudentContextPrompt(studentContext)}
    "Harita Dedektifi" (Türkiye Coğrafyası, Yön Algısı ve Fonolojik Farkındalık) etkinliği oluştur.

    ZORUNLU PARAMETRELER:
    - ODAK BÖLGE: ${regionDesc}.
    - YÖNERGE ADEDİ: Her sayfa için tam ${itemCount || 8} adet özgün yönerge.
    - ZORLUK: ${difficulty}.
    - ŞART: ${cityVisibility}

    YÖNERGE ÜRETİM STRATEJİSİ (HİBRİT MANTIK):
    1. **Uzamsal Mantık:** "X şehrinin kuzeyindeki komşusunu bul ve maviye boya."
    2. **Fonolojik Farkındalık (Disleksi Odaklı):** "İsminde 'Ş' harfi geçen bir kıyı şehrini bul ve işaretle."
    3. **Coğrafi Nitelik:** "Denize kıyısı OLMAYAN ve 'A' ile başlayan bir şehri bul."
    4. **Görsel Tarama:** "Haritanın en doğusundaki işaretli şehri bul ve üzerine bir yıldız çiz."

    Zorluk Seviyesi Ayarı:
    - Başlangıç: Basit konum bulma ve boyama.
    - Orta: İki aşamalı yönergeler (Yön + Harf).
    - Zor: Üç katmanlı analiz (Bölge + Komşuluk + Fonoloji).
    - Uzman: İsimsiz harita üzerinde zihinsel rotasyon ve koordinat takibi.

    ÇIKTI FORMATI:
    - title: "Harita Dedektifi: ${regionDesc}"
    - instruction: "Haritayı incele ve bir dedektif gibi gizli şehirleri yönergelere göre bul."
    - pedagogicalNote: "Bu çalışma; görsel tarama, uzamsal konumlandırma, fonolojik ayrıştırma ve zihinsel haritalama becerilerini profesyonel düzeyde destekler."
    - instructions: [string array]

    SADECE JSON DÖNDÜR.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                instructions: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ['title', 'instruction', 'instructions']
        }
    };

    const raw = await generateWithSchema(prompt, schema, 'gemini-3-flash-preview') as any[];

    // Şehir veritabanını al ve bölgeye göre filtrele
    const { CALIBRATED_CITIES } = await import('../offlineGenerators/mapDetective');
    const filteredCities = emphasizedRegion === 'all' 
        ? CALIBRATED_CITIES 
        : CALIBRATED_CITIES.filter(c => c.region === emphasizedRegion);

    return raw.map((item: any) => ({
        ...item,
        cities: filteredCities,
        settings: { 
            showCityNames: showCityNames ?? true, 
            markerStyle: options.markerStyle || 'circle', 
            difficulty,
            emphasizedRegion
        }
    }));
};

export const generateFromRichPrompt = async (activityType: ActivityType, instructions: string, options: GeneratorOptions): Promise<any> => {
    const prompt = `
    ${PEDAGOGICAL_BASE}
    ${getStudentContextPrompt(options.studentContext)}
    GÖREV: "${activityType}" türünde, disleksi dostu bir materyal üret.
    MİMARİ: ${instructions}
    ÇIKTI: sections dizisi içeren JSON.
    `;
    const schema = { type: Type.OBJECT, properties: { title: { type: Type.STRING }, instruction: { type: Type.STRING }, sections: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { type: { type: Type.STRING }, title: { type: Type.STRING }, content: { type: Type.STRING }, items: { type: Type.ARRAY, items: { type: Type.STRING } } }, required: ['type'] } } }, required: ['title', 'sections'] };
    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

