export const generateOfflineMapDetective = async (options: GeneratorOptions): Promise<MapInstructionData[]> => {
    const { worksheetCount, difficulty, itemCount, emphasizedRegion, showCityNames, markerStyle } = options;
    const results: MapInstructionData[] = [];

    const cityPool = (emphasizedRegion && emphasizedRegion !== 'all')
        ? CALIBRATED_CITIES.filter(c => c.region === emphasizedRegion)
        : CALIBRATED_CITIES;

    const generateHeuristicRule = () => {
        const city = cityPool[getRandomInt(0, cityPool.length - 1)];
        const types = ['color', 'shape', 'logic'];
        const type = getRandomItems(types, 1)[0];

        if (type === 'color') return `${city.name} ilini bul ve kırmızı renge boya.`;
        if (type === 'shape') return `${city.name} ilinin üzerine küçük bir yıldız çiz.`;
        if (city.isCoastal) return `Denize kıyısı olan ${city.name} ilini bul ve daire içine al.`;
        return `${city.region} bölgesinde bulunan ${city.name} ilini işaretle.`;
    };

    for (let p = 0; p < worksheetCount; p++) {
        const count = itemCount || 8;
        const instructions = Array.from({ length: count }, () => generateHeuristicRule());

        results.push({
            title: `Harita Dedektifi: ${emphasizedRegion === 'all' ? 'Türkiye' : emphasizedRegion}`,
            instruction: "Harita üzerindeki gizli görevleri yönergelere göre tamamla.",
            pedagogicalNote: "Görsel tarama ve uzamsal algı becerilerini yerel verilerle destekler.",
            cities: cityPool.map(c => ({ ...c })),
            instructions,
            settings: {
                showCityNames: showCityNames !== undefined ? showCityNames : true,
                markerStyle: (markerStyle as any) || 'circle',
                difficulty,
                emphasizedRegion
            }
        });
    }

    return results;
};

