// NUMBER LOGIC RIDDLES (Offline Professional)
export const generateOfflineNumberLogicRiddles = async (options: GeneratorOptions): Promise<NumberLogicRiddleData[]> => {
    const { worksheetCount, numberRange, difficulty, gridSize, itemCount = 4, distractionLevel } = options;

    const [minRange, maxRange] = (numberRange || '1-50').split('-').map(Number);
    const pages: NumberLogicRiddleData[] = [];

    for (let p = 0; p < worksheetCount; p++) {
        const puzzles = [];
        let runningTotal = 0;

        for (let i = 0; i < itemCount; i++) {
            const n = getRandomInt(minRange, maxRange);
            const hints = [];

            // Intelligent Hint Generation based on number properties
            if (n % 2 === 0) hints.push("Ben bir çift sayıyım.");
            else hints.push("Ben bir tek sayıyım.");

            const mid = Math.floor((maxRange + minRange) / 2);
            if (n > mid) hints.push(`${mid}'den büyüğüm.`);
            else hints.push(`${mid}'den küçüğüm.`);

            if (gridSize && gridSize >= 3) {
                 const sumDigits = n.toString().split('').reduce((acc, curr) => acc + parseInt(curr), 0);
                 hints.push(`Rakamlarım toplamı ${sumDigits}'dir.`);
            }

            if (gridSize && gridSize >= 4 && n >= 10) {
                const tens = Math.floor(n / 10);
                hints.push(`Onlar basamağım ${tens % 2 === 0 ? 'çifttir' : 'tektir'}.`);
            }

            if (gridSize && gridSize >= 5) {
                if (n % 5 === 0) hints.push("5'in katıyım.");
                else hints.push("5'in katı değilim.");
            }

            // Evidence Boxes
            const boxes = Array.from({ length: 5 }, () => {
                return [getRandomInt(minRange, maxRange), getRandomInt(minRange, maxRange)];
            });
            // Inject target
            boxes[getRandomInt(0, 4)][0] = n;

            const distractors = new Set<number>();
            while(distractors.size < 3) {
                const d = getRandomInt(minRange, maxRange);
                if (d !== n) distractors.add(d);
            }
            const allOptions = shuffle([n.toString(), ...Array.from(distractors).map(d => d.toString())]);
            const correctLetter = ['A', 'B', 'C', 'D'][allOptions.indexOf(n.toString())];

            puzzles.push({
                riddle: hints.join(' '),
                boxes,
                options: allOptions,
                answer: `${correctLetter} - ${n}`,
                answerValue: n
            });

            runningTotal += n;
        }

        pages.push({
            title: "Sayısal Mantık Bilmeceleri",
            instruction: "Bilmeceleri çöz, doğru şıkkı bul ve tüm cevapların toplamıyla büyük kasa şifresine ulaş!",
            pedagogicalNote: "Bu çalışma; sayı hissi, ardışık işlem belleği ve tümdengelimsel muhakeme becerilerini klinik düzeyde destekler.",
            sumTarget: distractionLevel === 'high' ? runningTotal : 0,
            sumMessage: distractionLevel === 'high' ? `Doğru cevapların toplamı tam olarak ${runningTotal} olmalıdır.` : '',
            puzzles
        });
    }

    return pages;
};

